import { describe, it } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";
import {
	computeEffectiveAllowedTools,
	computeToolActivationArgs,
	computeToolPolicies,
	writeToolGuardExtension,
	type EffectiveTool,
} from "../../src/server/agent/tool-activation.ts";
import type { ScopedToolContext, ToolProvider } from "../../src/server/agent/tool-manager.ts";

type ProviderWithGroup = ToolProvider & { groupDir: string; baseDir: string };

const ctx: ScopedToolContext = { scopeKey: "project:alpha", projectId: "alpha" };

function piProvider(name: string): ProviderWithGroup {
	return { type: "pi-extension", providerKey: `pi-ext:project:alpha:pack:demo:${name}`, groupDir: "", baseDir: "" };
}

function mockToolManager() {
	const providers = new Map<string, ProviderWithGroup>([
		["read", { type: "builtin", tool: "read", groupDir: "filesystem", baseDir: "/mock/tools" }],
		["pi_demo", piProvider("pi_demo")],
	]);
	const availableTools = [
		{ name: "read", description: "Read files", group: "File System", hasRenderer: false },
		{
			name: "pi_demo",
			description: "Demo pi extension tool",
			group: "Pi Extensions",
			hasRenderer: false,
			providerType: "pi-extension",
			origin: "marketplace-pi-extension",
			originPackName: "Demo Pack",
			originPackId: "pack",
			providers: [{ providerKey: "pi-ext:project:alpha:pack:demo:pi_demo", packName: "Demo Pack", packId: "pack", listName: "demo", scope: "project" }],
		},
	];
	return {
		getAvailableTools: (scopedContext?: ScopedToolContext) => scopedContext?.scopeKey === ctx.scopeKey ? availableTools : availableTools.slice(0, 1),
		getToolByName: (name: string, scopedContext?: ScopedToolContext) => (scopedContext?.scopeKey === ctx.scopeKey ? availableTools : availableTools.slice(0, 1)).find((tool) => tool.name === name),
		getToolProvider: (name: string, scopedContext?: ScopedToolContext) => scopedContext?.scopeKey === ctx.scopeKey ? providers.get(name) : (name === "read" ? providers.get(name) : undefined),
		getToolProviders: (scopedContext?: ScopedToolContext) => {
			if (scopedContext?.scopeKey === ctx.scopeKey) return providers;
			return new Map([["read", providers.get("read")!]]);
		},
		getExtensionPath: (groupDir: string, filename: string) => path.join("/mock/tools", groupDir, filename),
	} as any;
}

function extensionPaths(args: string[]): string[] {
	return args.filter((_arg, i) => i > 0 && args[i - 1] === "--extension").map((p) => p.replace(/\\/g, "/"));
}

describe("pi-extension tool activation and policy integration", () => {
	it("includes discovered scoped pi tools by default and removes them only for never policy", () => {
		const tm = mockToolManager();

		const allowed = computeEffectiveAllowedTools(tm, undefined, undefined, undefined, ctx).map((tool) => tool.name);
		assert.ok(allowed.includes("read"));
		assert.ok(allowed.includes("pi_demo"));

		const denied = computeEffectiveAllowedTools(tm, { toolPolicies: { pi_demo: "never" } }, undefined, undefined, ctx).map((tool) => tool.name);
		assert.ok(!denied.includes("pi_demo"));
	});

	it("does not emit a Bobbit --extension for pi-extension providers", () => {
		const tm = mockToolManager();
		const warnings: string[] = [];
		const originalWarn = console.warn;
		console.warn = (message?: unknown) => { warnings.push(String(message)); };
		try {
			const tools: EffectiveTool[] = [{ kind: "pi-extension", name: "pi_demo" }];
			const result = computeToolActivationArgs(tools, tm, undefined, undefined, undefined, ctx);
			const exts = extensionPaths(result.args);
			assert.ok(exts.some((p) => p.endsWith("/_builtins/extension.ts")));
			assert.equal(exts.filter((p) => !p.endsWith("/_builtins/extension.ts")).length, 0);
			assert.equal(result.env.BOBBIT_BUILTIN_TOOLS, "");
			assert.deepEqual(warnings, []);
		} finally {
			console.warn = originalWarn;
		}
	});

	it("feeds ask and never pi tool policies into the guard", () => {
		const tm = mockToolManager();
		const policies = computeToolPolicies(tm, undefined, { toolPolicies: { pi_demo: "ask", read: "never" } }, undefined, ctx);
		assert.equal(policies.pi_demo.policy, "ask");
		assert.equal(policies.read.policy, "never");

		const guardPath = writeToolGuardExtension("pi-policy-session", tm, undefined, { toolPolicies: { pi_demo: "ask", read: "never" } }, undefined, [], undefined, ctx);
		assert.ok(guardPath, "expected guard extension path");
		const code = fs.readFileSync(guardPath!, "utf-8");
		assert.match(code, /pi_demo/);
		assert.match(code, /askPolicyNamesByLower/);
		assert.match(code, /neverPolicyNamesByLower/);
	});
});
